var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CARTOON_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>자유로운 군인 티모시 대위는 오늘도 음흉한 웃음을 띄고 있다!</color>","JPN":"<color=#ffd34c>自由奔放な軍人、ティモシー大尉は今日も陰険な笑みを浮かべている！</color>","ENG":"<color=#ffd34c>Captain Timothy, the carefree soldier, is smiling sinisterly today as well!</color>","TWN":"<color=#ffd34c>自由的軍人提摩西上尉今天也露出陰險的笑容！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CARTOON_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>아군, 적군 가리지 않는 그의 지뢰폭탄은 악마도 울고 갈 정도!</color>","JPN":"<color=#ffd34c>味方、敵を問わない彼の地雷爆弾は悪魔も泣くほど！</color>","ENG":"<color=#ffd34c>His mine bombs don't discriminate friend and foe, ruthless enough to even make the devil cry!</color>","TWN":"<color=#ffd34c>不分敵我布下的地雷炸彈，連惡魔都要哭泣！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CARTOON_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그는 지금도 대원들을 골탕 먹이기 위한 작전을 세우고 있는데….</color>","JPN":"<color=#ffd34c>彼は今も隊員に意地悪するための作戦を立てているが……</color>","ENG":"<color=#ffd34c>Even right as of this moment, he's scheming a plan to cause trouble for his unit...</color>","TWN":"<color=#ffd34c>現在也在策劃著捉弄隊員的計畫嗎……！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARTOON_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>티모시 대위! 부디 아군은 말려들게 하지 말아다오!</color>","JPN":"<color=#ffd34c>ティモシー大尉！　どうか味方は巻き込まないでおくれ！</color>","ENG":"<color=#ffd34c>Captain Timothy! Please don't let our allies get caught up in it again!</color>","TWN":"<color=#ffd34c>提摩西上尉！請千萬不要連累到我們的隊員！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARTOON_DOLL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>강습! 브레멘 동물전대, 다음 화도 기대해 주세요.</color>","JPN":"<color=#ffd34c>強襲！　ブレーメン動物戦隊、次回もお楽しみに。</color>","ENG":"<color=#ffd34c>On the next episode of Charge! Town Soldiers of Bremen!</color>","TWN":"<color=#ffd34c>強襲！布萊梅動物戰隊，下一集，敬請期待！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"다음 비디오가 마지막이었지?","JPN":"次のビデオが最後だったよね？","ENG":"There's only one more video left, right?","TWN":"下一集應該就是最後一集吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"마지막은 항상 남겨놔야 해. 그래야 언제나 설레는 마음으로 지낼 수 있다구!","JPN":"最後は残しておかないと。そうすればいつもワクワクした気持ちでいられるから！","ENG":"I should leave that be. So I can always be excited for the next one!","TWN":"最後一個總要留著。這樣才能一直懷著期待的心情生活！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"내가 들은건데, 재밌는 건 무조건 아껴두는 거랬어.","JPN":"楽しいことは絶対残しておいた方がいいって、聞いたんだ。","ENG":"I heard that you should always savor the best parts for last.","TWN":"我聽人家說，有趣的東西一定要留到最後。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"그래야 살아있는 이유 하나를 간직하는 셈인거니까!","JPN":"生きている理由が一つできるわけだから！","ENG":"That's how you keep another reason to be alive!","TWN":"這樣就又多了一個活著的理由！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHASHA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"역시 이건 다음에 봐야겠다.","JPN":"やっぱりこれは後で見よう。","ENG":"I think I'll wait to watch the next one.","TWN":"果然還是留到下次看吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>음… 무슨 말부터 해야 하지?</color>","JPN":"<color=#ffd34c>うーん……何から話したらいいかな？</color>","ENG":"<color=#ffd34c>Mm... What should I start with...?</color>","TWN":"<color=#ffd34c>嗯……該從哪裡開始說呢？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L18_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>헤헷. 안녕 마브카? 내가 누군지 알아?</color>","JPN":"<color=#ffd34c>へへっ。ハロー、マブカ。私が誰かわかる？</color>","ENG":"<color=#ffd34c>Hehe. Hi, Mavka. Can you tell who this is?</color>","TWN":"<color=#ffd34c>嘿嘿，哈囉，瑪卡？你知道我是誰嗎？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>바로~ 마브카의 가장 친한 친구 사샤!</color>","JPN":"<color=#ffd34c>マブカの大親友、サシャだよ！</color>","ENG":"<color=#ffd34c>It's your best friend, Sasha!</color>","TWN":"<color=#ffd34c>我就是～～瑪卡最好的朋友莎夏！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>아잇! 걔가 바보도 아니고, 내 목소릴 못 알아들을 리 없잖아…</color>","JPN":"<color=#ffd34c>もう！　あの子はバカじゃないし、私の声がわからないわけないじゃない……</color>","ENG":"<color=#ffd34c>Ugh... She's not stupid. I'm sure she'll know whose voice this is–!</color>","TWN":"<color=#ffd34c>哎呀！她又不是傻瓜，不可能聽不出我的聲音……</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>다시 다시….</color>","JPN":"<color=#ffd34c>やり直し、やり直し……</color>","ENG":"<color=#ffd34c>Let's try this again...</color>","TWN":"<color=#ffd34c>再來一次……</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>흠흠! 생일 축하해 마브카.</color>","JPN":"<color=#ffd34c>おほん！　お誕生日おめでとう、マブカ。</color>","ENG":"<color=#ffd34c>Ahem! Happy birthday, Mavka.</color>","TWN":"<color=#ffd34c>咳咳！生日快樂，瑪卡。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>생일은 너와 내가 처음 만난 날로 정했어.</color>","JPN":"<color=#ffd34c>あなたと初めて出会った日を誕生日にしたよね。</color>","ENG":"<color=#ffd34c>I decided that your birthday is the day we first met.</color>","TWN":"<color=#ffd34c>我把生日定在你我第一次見面的那天。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>그러니까 나도 너랑 생일이 같다구~</color>","JPN":"<color=#ffd34c>だから、私もあなたと誕生日が一緒～</color>","ENG":"<color=#ffd34c>And it turns out, you and I have the same birthday!</color>","TWN":"<color=#ffd34c>所以你和我是同一天生日喔～</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>에헤헤… 그럼 내 선물도 기대해도 될까?</color>","JPN":"<color=#ffd34c>えへへ……じゃあ、私へのプレゼントも楽しみにしていい？</color>","ENG":"<color=#ffd34c>Ehehe... Can I be expecting to get a present from you too?</color>","TWN":"<color=#ffd34c>嘿嘿……那我也可以期待我的禮物嗎？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>선물은 꼭 물건일 필요는 없어. 맛있는 음식을 대접해 주는 것도 좋지.</color>","JPN":"<color=#ffd34c>プレゼントはべつに物じゃなくてもいいんだよ。美味しい物をご馳走してくれるのでもいい。</color>","ENG":"<color=#ffd34c>The gift doesn't have to be an object. I'm fine with you treating me out to some good food too.</color>","TWN":"<color=#ffd34c>也不一定非得送我禮物啦，請我吃美食也不錯。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>맛있는 음식을 대접해주고 함께 먹으면, 정말 멋진 선물이 될 것 같아! </color>","JPN":"<color=#ffd34c>美味しい物を一緒に食べるのも、本当に素敵なプレゼントになると思う！</color>","ENG":"<color=#ffd34c>And eating it together will be the best gift ever!</color>","TWN":"<color=#ffd34c>買好吃的一起享用，感覺會是個很棒的禮物！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>헤헤. 마브카가 편한대로 해도 돼. 앞으로 같이 지낼 날은 많잖아? </color>","JPN":"<color=#ffd34c>へへ。マブカの好きにしていいんだよ。これからずっと一緒に過ごすでしょう？</color>","ENG":"<color=#ffd34c>Hehe. You can do as you please, Mavka. Besides, we still have a lot more days ahead of us!</color>","TWN":"<color=#ffd34c>嘿嘿，瑪卡你隨意就好，以後我們相處的日子還多著呢？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>앞으로 크리스마스, 어린이날, 발렌타인 전부 챙겨야 하니까 바빠지겠네.</color>","JPN":"<color=#ffd34c>これからクリスマス、子どもの日、バレンタインまで全部お祝いするから、忙しくなるね。</color>","ENG":"<color=#ffd34c>There are Christmas, Children's Day, Valentine’s Day... It's going to be so busy celebrating all of them!</color>","TWN":"<color=#ffd34c>以後耶誕節、兒童節、情人節都要準備，看來會很忙呢。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>헤헤… 너무 많나? 그래도 설레지 않아?</color>","JPN":"<color=#ffd34c>へへ……多すぎるよね？　でもワクワクしない？</color>","ENG":"<color=#ffd34c>Hehe... Maybe it's too much? But aren't you excited about them?</color>","TWN":"<color=#ffd34c>哈哈……會太多嗎？不過你不覺得很期待嗎？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>벌써부터 기대된다. 앞으로도 잘 부탁할게.</color>","JPN":"<color=#ffd34c>今から楽しみだよ。これからもよろしくね。</color>","ENG":"<color=#ffd34c>I know I am. So I hope we stay good friends forever.</color>","TWN":"<color=#ffd34c>我已經開始期待囉，以後也請多多關照！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SHASHA_DOLL_NPC_VIOCE","text":{"KOREA":"<color=#ffd34c>그럼 다시, 생일 축하해~</color>","JPN":"<color=#ffd34c>それじゃあ、改めて。お誕生日おめでとう～</color>","ENG":"<color=#ffd34c>Then, once again, happy birthday!</color>","TWN":"<color=#ffd34c>那麼，再一次祝你生日快樂～</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤가 먹을 음식... 아직 많이 남아 있었네….","JPN":"サシャの食べ物……まだたくさん残っていたんだ……","ENG":"There are still lots of food... that you have to eat, Sasha...","TWN":"莎夏要吃的食物……還剩很多呢……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>어때 어때? 열심히 만들어본건데, 맛 평가는…?!</color>","JPN":"<color=#ffd34c>どう、どう？　頑張って作ってみたんだけど、味の感想は……！？</color>","ENG":"<color=#ffd34c>What do you think? I worked so hard to make it, and how does it taste...?!</color>","TWN":"<color=#ffd34c>怎麼樣？怎麼樣？我很努力做的，口味如何……？！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"솔직히... 잘 모르겠어.","JPN":"正直……よくわかんない。","ENG":"Honestly... I'm not sure.","TWN":"說實話……我也不知道。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>으엑…! 빈말이라도 맛있다고 해주지!</color>","JPN":"<color=#ffd34c>ええっ……！　お世辞でもいいから美味しいって言ってよ！</color>","ENG":"<color=#ffd34c>Egh...! You could've just said that it was good!</color>","TWN":"<color=#ffd34c>呃……！說幾句客套話也好嘛！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"후훗. 그렇게나 나랑 같이 먹고 싶었었구나…?","JPN":"ふふっ。そんなに私と一緒に食べたかったんだ……？","ENG":"Haha. You really wanted to eat this with me, didn't you?","TWN":"呵呵，你這麼想和我一起吃嗎……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"하지만, 음식을 먹을 수 없는 나에게 빵을 먹였으니, 벌을 줘야겠어.","JPN":"でも、食べ物を食べられない私にパンを食べさせたんだから、罰を与えないと。","ENG":"But since you shoved bread into my mouth when I can't eat food. I'll have to punish you.","TWN":"但是，讓不能吃東西的我吃麵包，得懲罰你。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"바로 내가 잠들 때까지 무릎배개를 해줘야 하는 벌이야.","JPN":"私が眠るまで膝枕しないといけない罰だよ。","ENG":"Your punishment is to let me use your lap as a pillow until I fall asleep.","TWN":"罰你讓我躺你的大腿，直到我睡著為止。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아이 참, 먹고 바로 누우면 소가 된다구!</color>","JPN":"<color=#ffd34c>もう、食べてすぐ寝転ぶと牛になるよ！</color>","ENG":"<color=#ffd34c>Ugh, it's a bad habit to eat and lay down immediately!</color>","TWN":"<color=#ffd34c>哎呀，吃完就躺下會變成豬的！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……상관없어.","JPN":"……別にいいよ。","ENG":"...It doesn’t matter.","TWN":"……我不管。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"사샤의 무릎 위에서 자고 싶어졌는걸.","JPN":"サシャの膝の上で寝たくなったの。","ENG":"I just want to fall asleep on your lap.","TWN":"我想在莎夏的腿上睡覺。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에헤헤. 처음엔 불편해하더니, 이제야 솔직해지는구나?</color>","JPN":"<color=#ffd34c>えへへ。最初は居心地悪そうだったのに、やっと素直になったんだ？</color>","ENG":"<color=#ffd34c>Ehehe. You were uncomfortable about it at first, but you seem to like it now, don't you?</color>","TWN":"<color=#ffd34c>噗哈哈哈，剛開始還扭扭捏捏的，現在終於可以誠實表達自己的想法啦？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우리 귀여운 새침데기 마브카~</color>","JPN":"<color=#ffd34c>可愛いおすましマブカ～</color>","ENG":"<color=#ffd34c>Our cute, sassy Mavka...!</color>","TWN":"<color=#ffd34c>瑪卡是個可愛的傲嬌鬼～</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마브카를 위해 특별히 허락해줄게. 불편하진 않아?</color>","JPN":"<color=#ffd34c>マブカのために特別に許可してあげる。不便じゃない？</color>","ENG":"<color=#ffd34c>I'll allow it just for you, Mavka. Are you comfy?</color>","TWN":"<color=#ffd34c>好吧，我就特別允許你躺在我的腿上，但你不覺得這樣不好睡嗎？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"……응. 아주 편안해.","JPN":"……うん。とても心地いい。","ENG":"...Yeah. It's so comfy.","TWN":"……不會，非常舒服。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에헤헤. 마브카는 내일 뭐 할거야?</color>","JPN":"<color=#ffd34c>えへへ。マブカは明日何する？</color>","ENG":"<color=#ffd34c>Ehehe. What are you going to do tomorrow, Mavka?</color>","TWN":"<color=#ffd34c>嘿嘿嘿，瑪卡明天打算做什麼呢？</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"내일이 되면 생각해볼게.","JPN":"明日になったら考えてみる。","ENG":"I'll think about that tomorrow.","TWN":"唔……明天……再想吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>에헤헤, 알았어. 그럼 내일 같이 생각해보자!</color>","JPN":"<color=#ffd34c>えへへ、わかった。じゃあ、明日一緒に考えようね！</color>","ENG":"<color=#ffd34c>Ehehe, okay. Then let's think about it together!</color>","TWN":"<color=#ffd34c>嘿嘿嘿，好，那明天一起想吧！</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>난 자고 있는 마브카의 귀여운 얼굴 좀 감상하다 자야지~</color>","JPN":"<color=#ffd34c>私は寝てるマブカの可愛い顔を観賞してから寝よう～</color>","ENG":"<color=#ffd34c>I'm going to sleep after watching the cute face you make when you sleep!</color>","TWN":"<color=#ffd34c>我要欣賞一下瑪卡可愛的睡顏再睡～</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오늘도 좋은 꿈 꿔.</color>","JPN":"<color=#ffd34c>今日もいい夢を見てね。</color>","ENG":"<color=#ffd34c>I hope you have a good dream.</color>","TWN":"<color=#ffd34c>今晚也做個好夢吧。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHASHA_DOLL_NULL_NULL","text":{"KOREA":"<color=#ffd34c>잘 자. 마브카.</color>","JPN":"<color=#ffd34c>おやすみ、マブカ。</color>","ENG":"<color=#ffd34c>Sweet dreams, Mavka.</color>","TWN":"<color=#ffd34c>晚安，瑪卡。</color>"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"너도 좋은 꿈 꿔.","JPN":"あなたもいい夢を見て。","ENG":"You too.","TWN":"你也做個好夢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"잘 자….","JPN":"おやすみ……","ENG":"Sweet dreams...","TWN":"晚安……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"나의 친구… 사샤.","JPN":"私の友だち……サシャ。","ENG":"Sasha... My friend.","TWN":"我的朋友……莎夏。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};